import java.util.TreeSet;

class ExamRoom {

    private int n;
    private TreeSet<Integer> seats;

    public ExamRoom(int n) {
        this.n = n;
        this.seats = new TreeSet<>();
    }

    public int seat() {
        if (seats.isEmpty()) {
            seats.add(0);
            return 0;
        }

        int maxDist = 0;
        int seat = 0;

        int prev = 0;
        for (int curr : seats) {
            int dist = (curr - prev) / 2;
            if (dist > maxDist) {
                maxDist = dist;
                seat = prev + dist;
            }
            prev = curr;
        }

        int lastDist = n - 1 - prev;
        if (lastDist > maxDist) {
            seat = prev + lastDist;
        }

        seats.add(seat);
        return seat;
    }

    public void leave(int p) {
        seats.remove(p);
    }
}
```

efficiency: HIGH
time complexity: O(log n) for seat, O(log n) for leave
space complexity: O(n)
energy implications: LOW
